class Solution {
public:
    string strWithout3a3b(int a, int b) {
        string result;
        while (a > 0 || b > 0) {
            string temp = result;
            if (result.size() >= 2 && result.substr(result.size() - 2) == "aa") {
                if (b > 0) {
                    result += 'b';
                    b--;
                } else {
                    result += 'a';
                    a--;
                }
            } else if (result.size() >= 2 && result.substr(result.size() - 2) == "bb") {
                if (a > 0) {
                    result += 'a';
                    a--;
                } else {
                    result += 'b';
                    b--;
                }
            } else if (a >= b) {
                result += 'a';
                a--;
            } else {
                result += 'b';
                b--;
            }
        }
        return result;
    }
};
```
